function Negative(First: number): number {
    return Add(~First, 1);
}

function Add(First: number, Second: number): number {
    return Second ? Add(First ^ Second, (First & Second) << 1) : First;
}

function Minus(First: number, Second: number): number {
    return Add(First, Negative(Second));
}

function Multi(First: number, Second: number): number {
    let Result: number = 0;
    while (Second) {
        if (Second & 1) {
            Result = Add(Result, First);
        }
        First = First << 1;
        Second = Second >> 1;
    }
    return Result;
}

function Divide(First: number, Second: number): number {
    let Result: number = 0;
    while (First >= Second) {
        First = Minus(First, Second);
        Result = Add(Result, 1);
    }
    return Result;
}

function StrLen(_String: string): number {
    return _String.length;
