function GetUpperCaseTable() { return "ABCDEFGHIJKLMNOPQRSTUVWXYZ"; }
function GetLowerCaseTable() { return GetUpperCaseTable().toLowerCase(); }
function GetNumberTable() { return "0123456789"; }
function GetSpicialTable() { return "+/="; }

interface Interpreter {
    InterpreterCode: string;
    InterpreterPassword: number;
    InterpreterIdentification: string;
}

class InterpreterMaker implements Interpreter {
    public InterpreterCode: string = "";
    public InterpreterPassword: number = 0;
    public InterpreterIdentification: string = "";

    constructor(public VMScript: string) {
        let InterpreterInfoStringList = VMScript.split("|");
        if (InterpreterInfoStringList.length == 3) {
            this.InterpreterCode = InterpreterInfoStringList[0];
            this.InterpreterPassword = +InterpreterInfoStringList[1];
            this.InterpreterIdentification = InterpreterInfoStringList[2];
        }
    }
}

class ScriptRuntime {
    static CallInnerFunction(FunctionName: string, Pars : string): string {
        return eval((FunctionName + "(\"" + Pars + "\")"));
    }

    static RegisterRuntimeFunction(InterpreterIdentification: string, InterpreterCode: string) {
        let _Function = "function ";
        let Brackets = "";
        let LeftBrackets = "";
        let RightBrackets = "";
        let Semicolon = "";

        let FinalCommand = _Function + InterpreterIdentification + Brackets + LeftBrackets + InterpreterCode + Semicolon + RightBrackets;
        this.EvalCode(FinalCommand);
    }

    static EvalCode(CodeToRun: string): string {
        let cover_eval = eval;
        return cover_eval(CodeToRun);
    }
}

class CB {
    private static _ShiftRight(Letter: string, NOfCaesarEncrypt: number) {
        var Ascii = Letter.charCodeAt(0);

        if (Ascii >= 65 && Ascii <= 90) {
            let FinalPos: number = (GetUpperCaseTable().indexOf(Letter) + NOfCaesarEncrypt) % GetUpperCaseTable().length;
            return GetUpperCaseTable().charAt(FinalPos);
        } else if (Ascii >= 97 && Ascii <= 122) {
            let FinalPos: number = (GetLowerCaseTable().indexOf(Letter) + NOfCaesarEncrypt) % GetLowerCaseTable().length;
            return GetLowerCaseTable().charAt(FinalPos);
        } else {
            return Letter;
        }
    }

    private static _ShiftLeft(Letter: string, NOfCaesarEncrypt: number) {
        var Ascii = Letter.charCodeAt(0);
        var LNOfCaesarEncrypt = NOfCaesarEncrypt % GetUpperCaseTable().length;
        if (Ascii >= 65 && Ascii <= 90) {
            let FinalPos: number = GetUpperCaseTable().indexOf(Letter);
            if (FinalPos - LNOfCaesarEncrypt < 0) {
                FinalPos = GetUpperCaseTable().length - (LNOfCaesarEncrypt - FinalPos);
                return GetUpperCaseTable().charAt(FinalPos);
            } else {
                return GetUpperCaseTable().charAt(FinalPos - LNOfCaesarEncrypt);
            }
        } else if (Ascii >= 97 && Ascii <= 122) {
            let FinalPos: number = GetLowerCaseTable().indexOf(Letter);
            if (FinalPos - LNOfCaesarEncrypt < 0) {
                FinalPos = GetLowerCaseTable().length - (LNOfCaesarEncrypt - FinalPos);
                return GetLowerCaseTable().charAt(FinalPos);
            } else {
                return GetLowerCaseTable().charAt(FinalPos - LNOfCaesarEncrypt);
            }
        }
        return Letter;
    }

    private static Shift(Letter: string, NOfCaesarEncrypt: number): string {
        if (NOfCaesarEncrypt < 0) {
            return CB._ShiftLeft(Letter, -NOfCaesarEncrypt);
        } else {
            return CB._ShiftRight(Letter, NOfCaesarEncrypt);
        }
    }

    private static Utf8Encode(StringToEncode: string): string {
        StringToEncode = StringToEncode.replace(/\r\n/g, "\n");
        let EncodedText: string = "";
        for (var n = 0; n < StringToEncode.length; n++) {
            var c = StringToEncode.charCodeAt(n);
            if (c < 128) {
                EncodedText += String.fromCharCode(c);
            } else if ((c > 127) && (c < 2048)) {
                EncodedText += String.fromCharCode((c >> 6) | 192);
                EncodedText += String.fromCharCode((c & 63) | 128);
            } else {
                EncodedText += String.fromCharCode((c >> 12) | 224);
                EncodedText += String.fromCharCode(((c >> 6) & 63) | 128);
                EncodedText += String.fromCharCode((c & 63) | 128);
            }
        }
        return EncodedText;
    }

    private static Utf8Decode(StringToDecode: string): string {
        var EncodedText = "";
        let i: number = 0, c: number = 0, c1: number = 0, c2: number = 0;
        while (i < StringToDecode.length) {
            c = StringToDecode.charCodeAt(i);
            if (c < 128) {
                EncodedText += String.fromCharCode(c);
                i++;
            } else if ((c > 191) && (c < 224)) {
                c1 = StringToDecode.charCodeAt(i + 1);
                EncodedText += String.fromCharCode(((c & 31) << 6) | (c1 & 63));
                i += 2;
            } else {
                c1 = StringToDecode.charCodeAt(i + 1);
                c2 = StringToDecode.charCodeAt(i + 2);
                EncodedText += String.fromCharCode(((c & 15) << 12) | ((c1 & 63) << 6) | (c2 & 63));
                i += 3;
            }
        }
        return EncodedText;
    }

    private static _Encode(StringToEncode: string, Base64EncodeNode: string): string {
        let output: string = "";
        var chr1, chr2, chr3, enc1, enc2, enc3, enc4;
        var i = 0;

        StringToEncode = CB.Utf8Encode(StringToEncode)
        while (i < StringToEncode.length) {
            chr1 = StringToEncode.charCodeAt(i++);
            chr2 = StringToEncode.charCodeAt(i++);
            chr3 = StringToEncode.charCodeAt(i++);
            enc1 = chr1 >> 2;
            enc2 = ((chr1 & 3) << 4) | (chr2 >> 4);
            enc3 = ((chr2 & 15) << 2) | (chr3 >> 6);
            enc4 = chr3 & 63;
            if (isNaN(chr2)) {
                enc3 = enc4 = 64;
            } else if (isNaN(chr3)) {
                enc4 = 64;
            }
            output = output + Base64EncodeNode.charAt(enc1) + Base64EncodeNode.charAt(enc2) + Base64EncodeNode.charAt(enc3) + Base64EncodeNode.charAt(enc4);
        }
        return output;
    }

    private static _Decode(StringToDecode: string, Base64EncodeNode: string): string {
        let output: string = "";
        var chr1, chr2, chr3, enc1, enc2, enc3, enc4;
        var i = 0;

        while (i < StringToDecode.length) {
            enc1 = Base64EncodeNode.indexOf(StringToDecode.charAt(i++));
            enc2 = Base64EncodeNode.indexOf(StringToDecode.charAt(i++));
            enc3 = Base64EncodeNode.indexOf(StringToDecode.charAt(i++));
            enc4 = Base64EncodeNode.indexOf(StringToDecode.charAt(i++));
            chr1 = (enc1 << 2) | (enc2 >> 4);
            chr2 = ((enc2 & 15) << 4) | (enc3 >> 2);
            chr3 = ((enc3 & 3) << 6) | enc4;
            output = output + String.fromCharCode(chr1);
            if (enc3 != 64) {
                output = output + String.fromCharCode(chr2);
            }
            if (enc4 != 64) {
                output = output + String.fromCharCode(chr3);
            }
        }
        return StringToDecode = CB.Utf8Decode(output);
    }

    public static Encode(String: string, PassWord: number): string {
        var Base64EncodeNode: string = "";

        for (var i: number = 0; i < GetUpperCaseTable().length; i++) {
            Base64EncodeNode += CB.Shift(GetUpperCaseTable()[i], PassWord);
        }

        for (var i: number = 0; i < GetLowerCaseTable().length; i++) {
            Base64EncodeNode += CB.Shift(GetLowerCaseTable()[i], PassWord);
        }

        Base64EncodeNode += GetNumberTable() + GetSpicialTable();

        return CB._Encode(String, Base64EncodeNode);
    }

    public static Decode(String: string, PassWord: number): string {
        var Base64EncodeNode: string = "";

        for (var i: number = 0; i < GetUpperCaseTable().length; i++) {
            Base64EncodeNode += CB.Shift(GetUpperCaseTable()[i], PassWord);
        }

        for (var i: number = 0; i < GetLowerCaseTable().length; i++) {
            Base64EncodeNode += CB.Shift(GetLowerCaseTable()[i], PassWord);
        }

        Base64EncodeNode += GetNumberTable() + GetSpicialTable();

        return CB._Decode(String, Base64EncodeNode);
    }
}

class InterpreterManager {
    static LoadScript(VMScript: string) {
        let InterpreterStringList = VMScript.split(";");
        for (let EachInterpreter of InterpreterStringList) {
            InterpreterManager.RegisterInterpreter(new InterpreterMaker(EachInterpreter));
        }
    }

    static RegisterInterpreters(InnerInterpreterList: Array<Interpreter>) {
        for (let Interpreter of InnerInterpreterList) {
            InterpreterManager.RegisterInterpreter(Interpreter);
        }
    }

    static RegisterInterpreter(Interpreter: Interpreter) {
        if (Interpreter.InterpreterPassword != 0) {
            let TrueInterpreterCode = CB.Decode(Interpreter.InterpreterCode, Interpreter.InterpreterPassword);
            let TrueInterpreterIdentification = CB.Decode(Interpreter.InterpreterIdentification, Interpreter.InterpreterPassword);

            ScriptRuntime.RegisterRuntimeFunction(TrueInterpreterIdentification, TrueInterpreterCode);
        } else {
            ScriptRuntime.RegisterRuntimeFunction(Interpreter.InterpreterIdentification, Interpreter.InterpreterCode);
        }
    }

    static CallInterpreter(InterpreterName: string,  Pars : string): string {
        return ScriptRuntime.CallInnerFunction(InterpreterName, Pars)
    }
}

